import React from "react";
import { Link, useLocation } from "react-router-dom";

function Navbar() {
  const location = useLocation();

  const links = [
    { name: "Dashboard", path: "/", icon: "📊" },
    { name: "Authority", path: "/authority", icon: "👥" },
    { name: "Bin", path: "/bin", icon: "🗂️" },
    { name: "Driver", path: "/driver", icon: "🚗" },
    { name: "User", path: "/user", icon: "👤" },
    { name: "Vehicle", path: "/vehicle", icon: "🚛" },
    { name: "Stitch UI", path: "/stitch-preview", icon: "🎨" },
  ];

  return (
    <aside className="sidebar">
      <div className="sidebar-brand">
        <span className="brand-icon">♻️</span>
        <span className="brand-text">Wastey</span>
      </div>

      <nav className="sidebar-nav">
        {links.map((link) => (
          <Link
            key={link.name}
            to={link.path}
            className={`sidebar-link ${
              location.pathname === link.path ? "active" : ""
            }`}
          >
            <span className="sidebar-icon">{link.icon}</span>
            {link.name}
          </Link>
        ))}
      </nav>
    </aside>
  );
}

export default Navbar;
